using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ── AddItem ────────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-001", 2, 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 3, 5.00m);

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-001", 2, 10.00m);

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_ZeroQuantity_Throws()
    {
        _cart.AddItem("SKU-001", 0, 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativeQuantity_Throws()
    {
        _cart.AddItem("SKU-001", -1, 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativePrice_Throws()
    {
        _cart.AddItem("SKU-001", 1, -5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void AddItem_NullSku_Throws()
    {
        _cart.AddItem(null!, 1, 10.00m);
    }

    // ── RemoveItem ─────────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_DecreasesTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 20.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_TotalIsZero()
    {
        _cart.AddItem("SKU-001", 2, 15.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveItem_NonexistentSku_Throws()
    {
        _cart.RemoveItem("SKU-MISSING");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void RemoveItem_NullSku_Throws()
    {
        _cart.RemoveItem(null!);
    }

    // ── CalculateTotal ─────────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 2, 5.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(10.00m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ────────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m,
            "Total should be reduced after applying a coupon.");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_InvalidCode_Throws()
    {
        _cart.ApplyCoupon("BOGUS");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void ApplyCoupon_NullCode_Throws()
    {
        _cart.ApplyCoupon(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_EmptyCode_Throws()
    {
        _cart.ApplyCoupon("");
    }

    [TestMethod]
    public void ApplyCoupon_TotalNeverNegative()
    {
        _cart.AddItem("SKU-001", 1, 1.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() >= 0m,
            "Total should never go below zero.");
    }
}

